import { useState, useEffect } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/GestionarSalas.css";

function GestionarSalas({ user }) {
  const [salas, setSalas] = useState([]);

  const obtenerSalas = async () => {
    try {
      const response = await fetch("http://localhost:3001/api/salas", {
        credentials: "include",
      });
      const data = await response.json();
      setSalas(data);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    obtenerSalas();
  }, []);

  return (
    <div className="container">
      {/* Navbar */}
      <NavbarGestionSalas userRole={user?.rol || ""} />

      {/* Header */}
      <div className="header">
        <h2>Gestión de Salas</h2>
        <button className="btn-crear">Crear Sala</button>
      </div>

      {/* Grid de salas */}
      <div className="grid-salas">
        
        {/* Card especial */}
        <div className="card card-info">
          <div className="card-header">
            <span>Info de sala básica</span>
            <span className="icon">⚙️</span>
          </div>

          <div className="card-buttons">
            <button>Info</button>
            <button>Recursos</button>
          </div>
        </div>

        {/* Salas dinámicas */}
        {salas.map((sala, index) => (
          <div key={index} className="card">
            {sala.nombre}
          </div>
        ))}

      </div>

      {/* Footer */}
      <footer className="footer">
        Footer
      </footer>
    </div>
  );
}

export default GestionarSalas;
